/**
 * Mechanically-extracted Falstad/CircuitJS1 reference shapes.
 *
 * Reads fixtures/falstad-shapes.json (generated by scripts/falstad-extract/)
 * and provides draw functions and pin positions for analog component
 * shape comparison — with zero manual transcription.
 *
 * The JSON contains draw calls and pin positions in CircuitJS1 pixel coordinates.
 * This module converts them to grid units (÷16) for comparison with our TS
 * component rendering.
 *
 * To regenerate: bash scripts/falstad-extract/extract.sh
 */

import { readFileSync } from "fs";
import { join } from "path";
// ---------------------------------------------------------------------------
// Public types
// ---------------------------------------------------------------------------

interface Point {
  x: number;
  y: number;
}

export interface FalstadPinRef {
  label: string;
  x: number;
  y: number;
}

export interface FalstadTextRef {
  text: string;
  x: number; // grid coords (px × PX_TO_GRID)
  y: number;
}

// ---------------------------------------------------------------------------
// Drawing interface
// ---------------------------------------------------------------------------

export interface RefDrawContext {
  drawLine(x1: number, y1: number, x2: number, y2: number): void;
  drawPolygon(points: readonly Point[], filled: boolean): void;
  drawCircle(cx: number, cy: number, radius: number, filled: boolean): void;
  drawArc(
    cx: number,
    cy: number,
    radius: number,
    startAngle: number,
    endAngle: number,
  ): void;
  drawRect(
    x: number,
    y: number,
    width: number,
    height: number,
    filled: boolean,
  ): void;
}

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

const PX_TO_GRID = 1 / 16;

// ---------------------------------------------------------------------------
// JSON types
// ---------------------------------------------------------------------------

interface DrawCall {
  type: string;
  x1?: number; y1?: number; x2?: number; y2?: number;
  thick?: boolean;
  cx?: number; cy?: number; r?: number;
  start?: number; end?: number;
  x?: number; y?: number; w?: number; h?: number;
  points?: [number, number][];
  text?: string;
}

interface ComponentData {
  className: string;
  style: string;
  postCount: number;
  x: number; y: number; x2: number; y2: number;
  pins: Array<{ index: number; x: number; y: number }>;
  draws: DrawCall[];
}

// ---------------------------------------------------------------------------
// CircuitJS1 JSON key → TS registry type name
// ---------------------------------------------------------------------------

